// src/components/Dashboard.js
import React from 'react';
import './Dashboard.css';

const Dashboard = () => {
  const today = new Date();
  const options = { month: 'long', year: 'numeric' };
  const monthYear = today.toLocaleDateString('pt-BR', options);
  const day = today.getDate();
  const weekDayOptions = { weekday: 'long' };
  const weekDay = today.toLocaleDateString('pt-BR', weekDayOptions);

  return (
    <div className="dashboard">
      <div className="dashboard-item calendar">
        <h2>Agenda</h2>
        <div className="calendar-month">{monthYear}</div>
        <div className="calendar-day">{day}</div>
        <div className="calendar-weekday">{weekDay}</div>
      </div>
      <div className="dashboard-item">
        <h2>Tarefas</h2>
        <div className="circle" style={{ backgroundColor: getRandomColor() }}>
          <span>1</span>
        </div>
        <div className="index">Índice de Tarefas</div>
      </div>
      <div className="dashboard-item">
        <h2>Intimações</h2>
        <div className="circle" style={{ backgroundColor: getRandomColor() }}>
          <span>10</span>
        </div>
        <div className="index">Índice de Intimações</div>
      </div>
      <div className="dashboard-item">
        <h2>Andamentos</h2>
        <div className="circle" style={{ backgroundColor: getRandomColor() }}>
          <span>0</span>
        </div>
        <div className="index">Índice de Andamentos</div>
      </div>
      <div className="dashboard-item">
        <h2>Audiências</h2>
        <div className="circle" style={{ backgroundColor: getRandomColor() }}>
          <span>1</span>
        </div>
        <div className="index">Índice de Audiências</div>
      </div>
      <div className="dashboard-item">
        <h2>Compromissos</h2>
        <div className="circle" style={{ backgroundColor: getRandomColor() }}>
          <span>0</span>
        </div>
        <div className="index">Índice de Compromissos</div>
      </div>
    </div>
  );
};

// Função para gerar uma cor aleatória
const getRandomColor = () => {
  const letters = '0123456789ABCDEF';
  let color = '#';
  for (let i = 0; i < 6; i++) {
    color += letters[Math.floor(Math.random() * 16)];
  }
  return color;
};

export default Dashboard;
